#!/usr/bin/env node
/**
 * Fake `claude` shim for `eval/run.mjs` integration tests.
 *
 * Two modes:
 *   1. `--version`        — emit a static version string + exit 0.
 *      Used by the runner's `toolVersion()` probe.
 *   2. Anything else      — emit a pre-canned Claude Code stream-json
 *      transcript to stdout (one JSONL event per line) + exit 0.
 *
 * The transcript is identical in shape to the
 * `tests/fixtures/score-run/claude-todo.jsonl` fixture so the scorer's
 * Claude parser handles it without bespoke changes.
 */
import { writeFileSync, existsSync, mkdirSync } from "node:fs";
import { join } from "node:path";

const args = process.argv.slice(2);

if (args.includes("--version")) {
  process.stdout.write("2.1.133 (Claude Code)\n");
  process.exit(0);
}

const events = [
  {
    type: "system",
    subtype: "init",
    timestamp: "2026-05-13T18:23:00Z",
    cliVersion: "2.1.133",
  },
  {
    type: "user",
    timestamp: "2026-05-13T18:23:01Z",
    message: { role: "user", content: "Scaffold a todo app using @baerly/server." },
    promptId: "p1",
  },
  {
    type: "assistant",
    timestamp: "2026-05-13T18:23:05Z",
    requestId: "r1",
    message: {
      model: "claude-opus-4-7",
      stop_reason: "tool_use",
      usage: {
        input_tokens: 120,
        cache_creation_input_tokens: 4000,
        cache_read_input_tokens: 8000,
        output_tokens: 300,
      },
      content: [
        { type: "thinking", thinking: "Plan the work" },
        {
          type: "tool_use",
          id: "t1",
          name: "Write",
          input: {
            file_path: "apps/server/src/todos.ts",
            content: "// generated by fake-claude shim\n",
          },
        },
      ],
    },
  },
  {
    type: "user",
    timestamp: "2026-05-13T18:23:06Z",
    message: {
      role: "user",
      content: [{ type: "tool_result", tool_use_id: "t1", is_error: false }],
    },
    toolUseResult: { ok: true },
  },
  {
    type: "assistant",
    timestamp: "2026-05-13T18:23:10Z",
    requestId: "r2",
    message: {
      model: "claude-opus-4-7",
      stop_reason: "end_turn",
      usage: {
        input_tokens: 80,
        cache_creation_input_tokens: 200,
        cache_read_input_tokens: 12000,
        output_tokens: 150,
      },
      content: [{ type: "text", text: "Scaffold complete." }],
    },
  },
  {
    type: "system",
    subtype: "turn_duration",
    timestamp: "2026-05-13T18:23:11Z",
    durationMs: 10000,
  },
];

for (const event of events) {
  process.stdout.write(JSON.stringify(event) + "\n");
}

// Also touch a single file in the cwd so `git diff baseline final`
// produces a non-empty diff — mirrors a real-agent edit.
const cwd = process.cwd();
const srcDir = join(cwd, "apps", "server", "src");
if (!existsSync(srcDir)) {
  mkdirSync(srcDir, { recursive: true });
}
writeFileSync(
  join(srcDir, "todos.ts"),
  "// generated by fake-claude shim\nexport const todos = [];\n",
  "utf8",
);

process.exit(0);
